function parseXmlConfig($xmlString) {
    $simpleXml = simplexml_load_string($xmlString, 'SimpleXMLElement', LIBXML_NOERROR | LIBXML_NOWARNING);
    
    if ($simpleXml === false) {
        throw new Exception("Invalid XML configuration provided.");
    }

    $settings = [];
    foreach ($simpleXml->children() as $setting) {
        $key = (string) $setting->getName();
        $value = (string) $setting;
        $settings[$key] = $value;
    }

    return $settings;
}